package genxsolution.vms.vmsbackend.maintenance_management.maintenance_schedule.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_schedule.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_schedule.mapper.MaintenanceScheduleMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_schedule.repository.MaintenanceScheduleRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenanceScheduleService { private final MaintenanceScheduleRepository repository; private final MaintenanceScheduleMapper mapper; public MaintenanceScheduleService(MaintenanceScheduleRepository repository,MaintenanceScheduleMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenanceScheduleResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenanceScheduleResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceSchedule", String.valueOf(id))); } public MaintenanceScheduleResponse create(MaintenanceScheduleUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenanceScheduleResponse update(UUID id,MaintenanceScheduleUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceSchedule", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenanceSchedule", String.valueOf(id)); } }
